import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"洞冥草","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/洞冥草.md","filePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/洞冥草.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/0.无支线/洞冥草.md"};function l(_,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"洞冥草",tabindex:"-1"},[s("洞冥草 "),e("a",{class:"header-anchor",href:"#洞冥草","aria-label":'Permalink to "洞冥草"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),o('<h1 id="洞冥草-1" tabindex="-1">洞冥草 <a class="header-anchor" href="#洞冥草-1" aria-label="Permalink to &quot;洞冥草&quot;">​</a></h1><p>洞冥草<br> 价格：1000分<br> 天汉二年，帝升蒼龍閣，思仙術，召諸方士言遠国遐方之事。唯東方朔下席，操筆跪而進，帝曰：“大夫為朕言乎？”朔曰：“臣遊北極，至鐘火之山，日月所不照，有青龍銜燭火以照。山之四極，亦有園圃池苑，皆植異木異草。有明莖草，夜如金燈，折枝為炬，照見鬼物之形。仙人寧封常服此草，於夜暝時，輒見腹光通外，亦名洞冥草。”帝令剉此草為泥，以塗雲明之館。夜坐此館，不加燈燭。亦名照魅草。採以藉足，履水不沉。<br> 效果<br> 洞冥草，又叫照魅草。会发光，迅捷动作点燃后的一场景内，可以照见方圆5米内的所有灵体鬼物，视为【灵感视觉】效果。也能食用，服用后：服用者的身体会微微发光（这可能令潜行检定承受一定的环境减值）并永久获得【灵感视觉】。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
